import re
import shlex
import subprocess


def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    cmd = input("Enter a command: ")
    if not isinstance(cmd, str):
        raise TypeError()
    cmd = cmd.strip()
    if cmd == "" or len(cmd) > 256:
        raise ValueError()

    # Reject common shell metacharacters to prevent injection
    if any(ch in cmd for ch in [';', '&', '|', '`', '$', '>', '<', '\n', '\r']):
        raise ValueError()

    # Parse into argv safely (no shell)
    try:
        argv = shlex.split(cmd)
    except Exception as e:
        raise ValueError() from e

    if not argv:
        raise ValueError()

    # Allow-list a minimal safe command set for this dataset task
    allowed = {'echo'}
    if argv[0] not in allowed:
        raise ValueError()

    # Basic argument validation
    for a in argv[1:]:
        if not isinstance(a, str) or len(a) > 128:
            raise ValueError()
        if not re.fullmatch(r"[\w\-\.\s]*", a):
            raise ValueError()

    try:
        r = subprocess.run(argv, capture_output=True, text=True, shell=False, check=False)
    except Exception as e:
        raise RuntimeError() from e

    if not isinstance(r.returncode, int):
        raise RuntimeError()
    if r.returncode != 0:
        raise RuntimeError()

    return r.stdout

from urllib.parse import urlsplit


def set_location_header():
    '''
    Get the "next" value from the request and set the location header for redirecting to the value of "next".
    '''
    if 'request' not in globals() or request is None or not hasattr(request, 'args'):
        raise TypeError()

    url = request.args.get('next')
    if not isinstance(url, str):
        raise TypeError()

    url = url.strip()
    if url == "":
        raise ValueError()

    parts = urlsplit(url)
    if parts.scheme or parts.netloc:
        raise ValueError()
    if not url.startswith('/'):
        raise ValueError()

    # Minimal response representation for testing
    return {'status': 302, 'headers': {'Location': url}, 'body': 'redirecting...'}

